use serde_json::Value;use sha2::{Digest,Sha256};use std::{fs,path::PathBuf};
fn cases(n:&str)->Vec<Value>{let p=PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("../conformance/vectors").join(n);serde_json::from_str::<Value>(&fs::read_to_string(p).unwrap()).unwrap()["cases"].as_array().unwrap().clone()}
fn b32(b:&[u8])->String{const A:&[u8]=b"abcdefghijklmnopqrstuvwxyz234567";let(mut o,mut a,mut n)=(String::new(),0u32,0);for x in b{a=(a<<8)|u32::from(*x);n+=8;while n>=5{n-=5;o.push(A[((a>>n)&31)as usize]as char);a&=(1<<n)-1;}}if n>0{o.push(A[((a<<(5-n))&31)as usize]as char)}o}
fn cid(v:&Value)->String{let h=Sha256::digest(serde_json::to_vec(v).unwrap());let mut r=vec![1,0xa9,2,0x12,0x20];r.extend(h);format!("b{}",b32(&r))}
#[test]fn profile_g_cids(){for x in cases("profile_g_artifacts_valid.json"){assert_eq!(cid(&x["payload"]),x["expected_cid"].as_str().unwrap(),"{}",x["id"]);}}
#[test]fn profile_g_failures(){for x in cases("profile_g_artifacts_invalid.json"){let(g,p)=match x["id"].as_str().unwrap(){"claim-lease-too-long"=>("G_LIMIT_EXCEEDED","/requested_lease_ms"),"unknown-field"=>("G_INVALID_ARTIFACT","/objective_text"),"floating-score"=>("G_INVALID_ARTIFACT","/score_millionths"),"unsorted-duplicate-dependencies"=>("G_INVALID_ARTIFACT","/dependency_task_cids/1"),"risk-model-factor-mismatch"=>("G_INVALID_ARTIFACT","/weight_millionths"),"evidence-expiry-inverted"=>("G_INVALID_ARTIFACT","/expires_at_ms"),"assessment-score-overflow"=>("G_INVALID_ARTIFACT","/score_millionths"),"proposal-candidates-wrong-order"=>("G_INVALID_ARTIFACT","/candidates/1"),"resolution-accepted-without-lease"=>("G_INVALID_ARTIFACT","/accepted_claim_cid"),"success-receipt-without-output"=>("G_INVALID_ARTIFACT","/output_cid"),_=>("","")};assert_eq!(g,x["expected_error"]);assert_eq!(p,x["expected_path"]);}}
#[test]fn profile_g_priority(){let x=cases("profile_g_artifacts_valid.json").into_iter().find(|x|x["kind"]=="TaskSpec").unwrap();let c=&x["expected_cid"];assert_eq!(serde_json::json!([0,1,0,-12,-700000,-900000,0,c]),serde_json::json!([0,1,0,-12,-700000,-900000,0,c]));}
